package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Test that formatting error messages use user-friendly field names.
 * This addresses the issue where error messages showed internal field names
 * like "totalHoursAbs" instead of user-facing names like "offsetHours".
 */
class ErrorMessageTest {

    @Test
    fun testOffsetHoursErrorMessage() {
        // This test reproduces the issue reported in GitHub where formatting
        // with a missing offset field showed an obscure error message.
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val zone = TimeZone.of("America/New_York")
        val instant = Instant.parse("2023-01-15T10:30:00Z")

        // This should fail with a helpful error message about "offsetHours" not being set
        val exception = assertFailsWith<IllegalStateException> {
            readableFormat.format {
                setDateTime(instant.toLocalDateTime(zone))
                timeZoneId = zone.id
                // Note: NOT setting the offset fields, which causes the error
            }
        }

        // The error message should mention "offsetHours" (user-facing name)
        // not "totalHoursAbs" (internal name)
        assertTrue(
            exception.message?.contains("offsetHours") == true,
            "Error message should mention 'offsetHours', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("totalHoursAbs") == true,
            "Error message should not mention internal field name 'totalHoursAbs', but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetMinutesOfHourErrorMessage() {
        // Test that the error message for offsetMinutesOfHour is also user-friendly
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                // Not setting offsetMinutesOfHour
            }
        }

        assertTrue(
            exception.message?.contains("offsetMinutesOfHour") == true,
            "Error message should mention 'offsetMinutesOfHour', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("minutesOfHour") == true && 
            exception.message?.contains("offsetMinutesOfHour") != true,
            "Error message should not mention internal field name 'minutesOfHour' alone, but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetSecondsOfMinuteErrorMessage() {
        // Test that the error message for offsetSecondsOfMinute is also user-friendly
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            char(':')
            offsetSecondsOfMinute()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                offsetMinutesOfHour = 30
                // Not setting offsetSecondsOfMinute
            }
        }

        assertTrue(
            exception.message?.contains("offsetSecondsOfMinute") == true,
            "Error message should mention 'offsetSecondsOfMinute', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("secondsOfMinute") == true &&
            exception.message?.contains("offsetSecondsOfMinute") != true,
            "Error message should not mention internal field name 'secondsOfMinute' alone, but was: ${exception.message}"
        )
    }

    @Test
    fun testCorrectFormattingStillWorksWithOffset() {
        // Verify that proper formatting with offset fields still works correctly
        val format = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            char(' ')
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val result = format.format {
            year = 2023
            monthNumber = 1
            dayOfMonth = 15
            hour = 10
            minute = 30
            second = 0
            offsetHours = 5
            offsetMinutesOfHour = 30
        }

        assertEquals("2023-01-15 10:30:00 +05:30", result)
    }
}
"}

