/**
 * Test that reproduces the exact issue from the bug report.
 * The issue was that formatting with a missing offset field showed:
 * "Field totalHoursAbs is not set" instead of "Field offsetHours is not set"
 */
class IssueReproductionTest {

    @Test
    fun testOriginalIssueReproduction() {
        // This is the exact format from the issue report
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val zone = TimeZone.of("America/New_York")
        val instant = Instant.parse("2023-01-15T10:30:00Z")

        // This is the exact scenario from the issue:
        // Setting timeZoneId but not the offset fields
        val exception = assertFailsWith<IllegalStateException> {
            readableFormat.format {
                setDateTime(instant.toLocalDateTime(zone))
                timeZoneId = zone.id
                // NOT setting offset fields - this causes the error
            }
        }

        // Verify the error message is now readable
        val message = exception.message
        assertNotNull(message, "Exception should have a message")

        // The error message should mention the user-facing field name
        assertTrue(
            message.contains("offsetHours") || message.contains("offset"),
            "Error message should mention 'offsetHours' or 'offset', but was: $message"
        )

        // The error message should NOT mention the internal field name
        assertFalse(
            message.contains("totalHoursAbs"),
            "Error message should not mention internal name 'totalHoursAbs', but was: $message"
        )
    }

    @Test
    fun testProperFormattingStillWorks() {
        // Verify that when offset is properly set, formatting works correctly
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            char(' ')
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val zone = TimeZone.of("America/New_York")
        val instant = Instant.parse("2023-01-15T10:30:00Z")
        val offset = zone.offsetAt(instant)

        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            setOffset(offset)
        }

        // Should format successfully
        assertNotNull(result)
        assertTrue(result.isNotEmpty())
    }
